Rule.Source:
	
 	
  import sailpoint.object.Identity;
  import sailpoint.object.Link;
  import sailpoint.object.RoleTarget;
  import sailpoint.object.Assignment;
  import sailpoint.object.Bundle;
  import sailpoint.object.RoleAssignment;
  import sailpoint.object.Application;
  import sailpoint.tools.Util;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  static Log logger = LogFactory.getLog("rule.identity.accountselector.birthrightroleassignment");
  logger.debug("Entering Ascension-Rule-AccountSelector-BirthrightRoleAssignment");

  /* 
      Business Requirement:
      Check 1: If new account is needed or not
    */	 
  Link selectedLink = new Link();

  if(null!=identity)
  {
    String domainAD = identity.getAttribute("domain");
    List refLinks = identity.getLinks();
    String appType = "";
    String principalName = "";
    String domainofAcc = "";

    if(null != identity && !Util.isEmpty(refLinks)){
    String roleTargetAccountName = null;
	if(null != role && null != role.getName()) {
	List<Bundle> assignedRoleAssignments = identity.getActiveRoleAssignments(role.getName());
	if(!Util.isEmpty(assignedRoleAssignments)){ 
	List<Bundle> roleTargets = assignedRoleAssignments.get(0).getTargets();
	if(!Util.isEmpty(roleTargets)) {
	  roleTargetAccountName = roleTargets.get(0).getDisplayName();
	  }
	 }
	}
      String domainAD = identity.getAttribute("domain");
      for(Link link : refLinks){

        if(null != link  && null != link.getApplication()){

          appType = link.getApplication().getType();

          if(Util.isNotNullOrEmpty(appType) && Util.nullSafeCaseInsensitiveEq(appType,"Active Directory - Direct")){

            principalName = link.getAttribute("msDS-PrincipalName");

            domainofAcc = "";

            if(Util.isNotNullOrEmpty(principalName)){
              domainofAcc = getDomain(principalName);
            }

            if(Util.nullSafeCaseInsensitiveEq(domainofAcc,domainAD) || Util.nullSafeCaseInsensitiveEq(roleTargetAccountName,principalName)){
              selectedLink = link;
              break;
            }
          }
        }
      }
    }
  }
  return selectedLink;
  logger.debug("Exiting Ascension-Rule-AccountSelector-BirthrightRoleAssignment");
